function drawChart(){
 const c=document.getElementById('chart'),ctx=c.getContext('2d'),m=document.getElementById('chartMetric').value,h=progressHistory().filter(x=>x[m]!==''&&x[m]!=null).slice(-20);
 ctx.clearRect(0,0,c.width,c.height);ctx.strokeStyle='#294764';ctx.lineWidth=1;for(let i=0;i<5;i++){let y=25+i*45;ctx.beginPath();ctx.moveTo(35,y);ctx.lineTo(c.width-15,y);ctx.stroke()}
 if(!h.length){ctx.fillStyle='#9db0c8';ctx.font='18px sans-serif';ctx.fillText('Save progress entries to build this chart.',55,120);return}
 let vals=h.map(x=>+x[m]||0),max=Math.max(...vals,1),min=Math.min(...vals,0);ctx.strokeStyle='#4ade80';ctx.lineWidth=4;ctx.beginPath();
 vals.forEach((v,i)=>{let x=40+i*(c.width-70)/Math.max(1,vals.length-1),y=220-(v-min)/(Math.max(1,max-min))*175;if(i===0)ctx.moveTo(x,y);else ctx.lineTo(x,y);ctx.fillStyle='#4ade80';ctx.beginPath();ctx.arc(x,y,5,0,Math.PI*2);ctx.fill();if(i===0){ctx.beginPath();ctx.moveTo(x,y)}});
 ctx.stroke();
}
